|- style="text-align: center;" |
| style="font-weight:bold; background-color:gray;" | Grey
| colspan="2" style="font-weight:bold; background-color:green; color:white;" | Green
| colspan="2" style="font-weight:bold; background-color:limegreen" | Light Green
| colspan="2" style="font-weight:bold; background-color:lightgreen;" | Greenish White
| colspan="3" style="font-weight:bold; background-color:white;" | White
| colspan="2" style="font-weight:bold; background-color:pink;" | Light Pink
| colspan="2" style="font-weight:bold; background-color:lightpink;" | Pink
| colspan="2" style="font-weight:bold; background-color:lightcoral;" | Light Red
| style="font-weight:bold; background-color:red; color:white;" | Red
| style="font-weight:bold; background-color:darkred; color:white;" | Deep Red
| style="font-weight:bold; background-color:magenta; color:white;" | Magenta
|}
